    31→final class PauseController {
    32→    private let queue = DispatchQueue(label: "PauseController")
    33→    private var startTime: CFTimeInterval?
    34→    private var pauseStart: CFTimeInterval?
    35→    private var totalPaused: CFTimeInterval = 0
    36→    private var paused = false
    37→
    38→    func start() {
    39→        queue.sync {
    40→            startTime = CACurrentMediaTime()
    41→            pauseStart = nil
    42→            totalPaused = 0
    43→            paused = false
    44→        }
    45→    }
    46→
    47→    func stop() {
    48→        queue.sync {
    49→            startTime = nil
    50→            pauseStart = nil
    51→            totalPaused = 0
    52→            paused = false
    53→        }
    54→    }
    55→
    56→    func pause() {
    57→        queue.sync {
    58→            guard !paused else { return }
    59→            paused = true
    60→            pauseStart = CACurrentMediaTime()
    61→        }
    62→    }
    63→
    64→    func resume() {
    65→        queue.sync {
    66→            guard paused, let pauseStart else { return }
    67→            let now = CACurrentMediaTime()
    68→            totalPaused += now - pauseStart
    69→            self.pauseStart = nil
    70→            paused = false
    71→        }
    72→    }
    73→
    74→    func shouldDropSamples() -> Bool {
    75→        queue.sync { paused }
    76→    }
    77→
    78→    func currentOffset() -> CMTime {
    79→        queue.sync {
    80→            CMTimeMakeWithSeconds(totalPaused, preferredTimescale: 1_000_000_000)
    81→        }
    82→    }
    83→
    84→    func currentTimelineSeconds() -> Double {
    85→        queue.sync {
    86→            guard let startTime else { return 0 }
    87→            let now = CACurrentMediaTime()
    88→            let pausedDuration = paused ? now - (pauseStart ?? now) : 0
    89→            return max(0, now - startTime - totalPaused - pausedDuration)
    90→        }
    91→    }
    92→}
