   107→final class MetadataLogger {
   108→    private let queue = DispatchQueue(label: "MetadataLogger")
   109→    private let pauseController: PauseController
   110→    private var outputURL: URL?
   111→    private var events: [BubbleEvent] = []
   112→
   113→    init(pauseController: PauseController) {
   114→        self.pauseController = pauseController
   115→    }
   116→
   117→    func start(outputURL: URL) {
   118→        queue.sync {
   119→            self.outputURL = outputURL
   120→            events.removeAll()
   121→        }
   122→    }
   123→
   124→    func logBubble(position: CGPoint, radius: CGFloat) {
   125→        let timestamp = pauseController.currentTimelineSeconds()
   126→        let event = BubbleEvent(
   127→            t: timestamp,
   128→            x: Double(position.x),
   129→            y: Double(position.y),
   130→            radius: Double(radius)
   131→        )
   132→        queue.async {
   133→            self.events.append(event)
   134→        }
   135→    }
   136→
   137→    func stop(completion: @escaping (Result<URL, Error>) -> Void) {
   138→        queue.async {
   139→            guard let url = self.outputURL else {
   140→                completion(.success(URL(fileURLWithPath: "")))
   141→                return
   142→            }
   143→            let formatter = ISO8601DateFormatter()
   144→            let metadata = RecordingMetadata(
   145→                version: 1,
   146→                createdAt: formatter.string(from: Date()),
   147→                events: self.events
   148→            )
   149→            do {
   150→                let encoder = JSONEncoder()
   151→                encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
   152→                let data = try encoder.encode(metadata)
   153→                try data.write(to: url, options: [.atomic])
   154→                completion(.success(url))
   155→            } catch {
   156→                completion(.failure(error))
   157→            }
   158→        }
   159→    }
   160→}
