   472→    private func ensureScreenCapturePermission() -> Bool {
   473→        if CGPreflightScreenCaptureAccess() {
   474→            needsScreenRecordingPermission = false
   475→            return true
   476→        }
   477→
   478→        let granted = CGRequestScreenCaptureAccess()
   479→        if granted {
   480→            needsScreenRecordingPermission = false
   481→            errorMessage = "Screen Recording permission was granted. Please quit and relaunch LoomClone."
   482→        } else {
   483→            needsScreenRecordingPermission = true
   484→            errorMessage = "Screen Recording permission is required. Enable LoomClone in System Settings → Privacy & Security → Screen Recording, then relaunch."
   485→        }
   486→        return false
   487→    }
