   502→    private func deleteRecordingFiles(screenURL: URL?, metadataURL: URL?) {
   503→        let fileManager = FileManager.default
   504→        for url in [screenURL, metadataURL] {
   505→            guard let url else { continue }
   506→            if fileManager.fileExists(atPath: url.path) {
   507→                try? fileManager.removeItem(at: url)
   508→            }
   509→        }
   510→    }
   511→
   512→    private func formatError(_ error: Error) -> String {
   513→        let nsError = error as NSError
   514→        var message = "\(nsError.localizedDescription) (\(nsError.domain) \(nsError.code))"
   515→        if let underlying = nsError.userInfo[NSUnderlyingErrorKey] as? NSError {
   516→            message += " → \(underlying.localizedDescription) (\(underlying.domain) \(underlying.code))"
   517→        }
   518→        return message
   519→    }
   520→}
